SELECT order_id, status
FROM order_versions
WHERE version = 1;

SELECT order_id, MAX(updated_at) AS latest_update
FROM order_versions
GROUP BY order_id;

SELECT company_name
FROM customers
WHERE city = 'Marseille';

SELECT COUNT(order_id) AS order_count
FROM order_versions
WHERE status = 'shipped';

SELECT COUNT(*) AS total_versions
FROM order_versions
WHERE order_id = 0;

SELECT version, status
FROM order_versions
WHERE order_id = 1;

SELECT status, COUNT(order_id) AS order_count
FROM order_versions
GROUP BY status;

SELECT order_id, version, status, updated_at, changes
FROM order_versions
ORDER BY updated_at DESC;

SELECT SUM(oi.quantity * oi.unit_price) AS total_revenue
FROM order_items oi
WHERE oi.quantity > 1;

SELECT product_id, SUM(quantity) AS total_quantity
FROM order_items
GROUP BY product_id;
